          check(!glimspinnerBtn.disabled && !driftcatcherBtn.disabled, 'PURCHASE_BUTTONS_ENABLED');

          var canvasCtx = canvas.getContext('2d');
          var checksumBefore = 0;
          if (canvasCtx) {
            var sampleImageData = canvasCtx.getImageData(10, 10, 40, 40);
            for (var i = 0; i < sampleImageData.data.length; i += 4) {
              checksumBefore += sampleImageData.data[i] + sampleImageData.data[i+1] + sampleImageData.data[i+2] + sampleImageData.data[i+3];
            }
          }

          glimspinnerBtn.click();
          window.setTimeout(function () {
            try {
